router.beforeEach((to, from, next) => {
  // 有标题就赋标题值，没有就设置默认值
  if (to.meta.title) {
    // to.meta.title meta元数据的title值

    // 做一层拷贝，防止响应式，将类型转化为 any 类型
    let title:any;
    title = to.meta.title
    
    document.title = title
  } else {
    document.title = '刘朝刚——个人网站'
  }

  // 更改小导航标题
  switch(to.name) {
    // to.name值为当前导航name值
    ...
  }

  // 路由继续跳转，正常运行必须执行
  next()
});`
